/*@ Extern Coq (string_equal_spec : list Z -> list Z -> Z) */
/*@ Import Coq Require Import string_equal */

int string_equal(char *a, char *b)
/*@ With la lb na nb
    Require
      0 <= na && na < INT_MAX &&
      0 <= nb && nb < INT_MAX &&
      (forall (k: Z), (0 <= k && k < na) => la[k] != 0) &&
      (forall (k: Z), (0 <= k && k < nb) => lb[k] != 0) &&
      CharArray::full(a, na + 1, app(la, cons(0, nil))) *
      CharArray::full(b, nb + 1, app(lb, cons(0, nil)))
    Ensure
      __return == string_equal_spec(la, lb) &&
      CharArray::full(a, na + 1, app(la, cons(0, nil))) *
      CharArray::full(b, nb + 1, app(lb, cons(0, nil)))
*/
{
    int i = 0;

    while (1) {
        if (a[i] == 0 || b[i] == 0) {
            break;
        }
        if (a[i] != b[i]) {
            return 0;
        }
        i++;
    }

    if (a[i] == 0 && b[i] == 0) {
        return 1;
    }
    return 0;
}

#include "../../verification_stdlib.h"
#include "../../verification_list.h"
#include "../../char_array_def.h"

void string_reverse_copy(int n, char *src, char *dst)
/*@ With l d
    Require
      0 <= n && n < INT_MAX &&
      (forall (k: Z), (0 <= k && k < n) => l[k] != 0) &&
      CharArray::full(src, n + 1, app(l, cons(0, nil))) *
      CharArray::full(dst, n + 1, d)
    Ensure
      CharArray::full(src, n + 1, app(l, cons(0, nil))) *
      CharArray::full(dst, n + 1, app(rev(l), cons(0, nil)))
*/
{
    int i;

    for (i = 0; i < n; ++i) {
        dst[i] = src[n - 1 - i];
    }
    dst[n] = 0;
}
